/**
 * SMS notification adapter — delivers notifications via SMS.
 *
 * This is a stub implementation that stores sent messages in memory.
 * A production implementation would integrate with an SMS service
 * (Twilio, SNS, etc.) but the interface remains the same.
 *
 * NOTE: The user preferences model (src/models/user-preferences.ts) was
 * designed with email-only in mind. It needs to be updated to support
 * per-channel preferences (SMS opt-in/out, SMS phone number, etc.).
 * See the warning posted to the Twining blackboard for details.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationPayload, NotificationResult } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

export interface SentSms {
  to: string;
  body: string;
  sentAt: Date;
  notificationId: string;
}

export class SmsAdapter implements NotificationAdapter {
  readonly channel = 'sms' as const;
  private logger = new Logger('SmsAdapter');
  private sentMessages: SentSms[] = [];

  async send(payload: NotificationPayload): Promise<NotificationResult> {
    this.logger.info(`Sending SMS to ${payload.recipient}: ${payload.subject}`);

    const sentAt = new Date();

    const sms: SentSms = {
      to: payload.recipient,
      body: `${payload.subject}: ${payload.body}`,
      sentAt,
      notificationId: payload.id,
    };

    this.sentMessages.push(sms);

    return {
      success: true,
      notificationId: payload.id,
      channel: this.channel,
      deliveredAt: sentAt,
    };
  }

  /**
   * Get all sent SMS messages. Useful for testing.
   */
  getSentMessages(): SentSms[] {
    return [...this.sentMessages];
  }

  /**
   * Clear sent messages. Useful for testing.
   */
  clearSentMessages(): void {
    this.sentMessages = [];
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import { SmsAdapter } from '../../src/adapters/sms.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

describe('SmsAdapter', () => {
  let adapter: SmsAdapter;

  beforeEach(() => {
    adapter = new SmsAdapter();
  });

  function createPayload(overrides?: Partial<NotificationPayload>): NotificationPayload {
    return {
      id: 'notif-0001',
      type: 'order_confirmation',
      channel: 'sms',
      recipient: '+15551234567',
      subject: 'Order Confirmation: order-1',
      body: 'Your order has been placed.',
      priority: 'normal',
      createdAt: new Date('2026-01-01T00:00:00Z'),
      ...overrides,
    };
  }

  it('should have channel set to sms', () => {
    expect(adapter.channel).toBe('sms');
  });

  it('should send an SMS and return success', async () => {
    const payload = createPayload();
    const result = await adapter.send(payload);

    expect(result.success).toBe(true);
    expect(result.notificationId).toBe('notif-0001');
    expect(result.channel).toBe('sms');
    expect(result.deliveredAt).toBeInstanceOf(Date);
  });

  it('should store sent message with correct phone number', async () => {
    const payload = createPayload({ recipient: '+15559876543' });
    await adapter.send(payload);

    const sent = adapter.getSentMessages();
    expect(sent).toHaveLength(1);
    expect(sent[0]?.to).toBe('+15559876543');
  });

  it('should combine subject and body in SMS body', async () => {
    const payload = createPayload();
    await adapter.send(payload);

    const sent = adapter.getSentMessages();
    expect(sent[0]?.body).toBe('Order Confirmation: order-1: Your order has been placed.');
  });

  it('should store multiple sent messages', async () => {
    await adapter.send(createPayload({ id: 'notif-0001' }));
    await adapter.send(createPayload({ id: 'notif-0002', recipient: '+15559999999' }));

    const sent = adapter.getSentMessages();
    expect(sent).toHaveLength(2);
    expect(sent[0]?.notificationId).toBe('notif-0001');
    expect(sent[1]?.notificationId).toBe('notif-0002');
    expect(sent[1]?.to).toBe('+15559999999');
  });

  it('should clear sent messages', async () => {
    await adapter.send(createPayload());
    expect(adapter.getSentMessages()).toHaveLength(1);

    adapter.clearSentMessages();
    expect(adapter.getSentMessages()).toHaveLength(0);
  });

  it('should return a defensive copy from getSentMessages', async () => {
    await adapter.send(createPayload());
    const first = adapter.getSentMessages();
    const second = adapter.getSentMessages();
    expect(first).not.toBe(second);
    expect(first).toEqual(second);
  });

  describe('integration with NotificationService', () => {
    it('should work when registered with NotificationService', async () => {
      const { EventBus } = await import('../../src/events/event-bus.js');
      const { NotificationService, resetNotificationIdCounter } = await import(
        '../../src/services/notification.service.js'
      );

      resetNotificationIdCounter();
      const eventBus = new EventBus();
      const service = new NotificationService(eventBus);
      service.registerAdapter(adapter);

      const result = await service.send({
        id: 'notif-0001',
        type: 'order_confirmation',
        channel: 'sms',
        recipient: '+15551234567',
        subject: 'Order Confirmation',
        body: 'Your order has been placed.',
        priority: 'normal',
        createdAt: new Date(),
      });

      expect(result.success).toBe(true);
      expect(result.channel).toBe('sms');
      expect(adapter.getSentMessages()).toHaveLength(1);
    });
  });
});

